--
-- Table structure for table `service_order_products`
--
DROP TABLE IF EXISTS `service_order_products`;
CREATE TABLE `service_order_products` (
  `new_id` int(11) NOT NULL AUTO_INCREMENT,
  `id` int(11) NOT NULL,
  `order_id` int(11) NOT NULL,
  `product_id` int(11) NOT NULL,
  `product_status` varchar(20) NOT NULL DEFAULT 'pending, rajtocom',
  `is_replacement` tinyint(1) NOT NULL DEFAULT 0,
  `sort_order` int(11) NOT NULL DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`new_id`),
  KEY `idx_service_order_products_order_replacement` (`order_id`,`is_replacement`,`sort_order`),
  KEY `idx_service_order_products_product_id` (`product_id`)
) ENGINE=InnoDB AUTO_INCREMENT=117 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

