--
-- Table structure for table `service_orders`
--
DROP TABLE IF EXISTS `service_orders`;
CREATE TABLE `service_orders` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `order_code` varchar(20) NOT NULL,
  `client_id` int(11) NOT NULL,
  `companies_products` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `company_id` int(10) unsigned DEFAULT NULL,
  `company_ids` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `company_product_map` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `product_id` int(11) DEFAULT NULL,
  `product_ids` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `product_status_map` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `repairing_status_map` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `issue_description_map` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`issue_description_map`)),
  `replacement_product_id` int(11) DEFAULT NULL,
  `replacement_product_ids` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `staff_id` int(11) DEFAULT NULL,
  `service_type` varchar(50) NOT NULL DEFAULT 'general',
  `issue_description` text DEFAULT NULL,
  `diagnosis_notes` text DEFAULT NULL,
  `repair_notes` text DEFAULT NULL,
  `warranty_status` enum('in_warranty','out_of_warranty','extended_warranty') DEFAULT 'out_of_warranty',
  `estimated_cost` decimal(10,2) DEFAULT NULL,
  `final_cost` decimal(10,2) DEFAULT NULL,
  `deposit_amount` decimal(10,2) DEFAULT 0.00,
  `payment_status` enum('pending','partially_paid','paid','refunded') NOT NULL DEFAULT 'pending',
  `estimated_delivery_date` date DEFAULT NULL,
  `actual_delivery_date` date DEFAULT NULL,
  `handover_type` enum('in_hand','courier','parcel_service') DEFAULT NULL,
  `handover_type_map` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `priority` enum('low','medium','high','urgent') DEFAULT 'medium',
  `rating` int(11) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `first_product_id` int(11) GENERATED ALWAYS AS (json_extract(`product_ids`,_utf8mb4'$[0]')) STORED,
  `status` int(11) NOT NULL,
  `product_status_dates_map` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_service_orders_order_code` (`order_code`),
  KEY `idx_service_orders_client_id` (`client_id`),
  KEY `idx_service_orders_staff_id` (`staff_id`),
  KEY `idx_service_orders_product_id` (`product_id`),
  KEY `idx_service_orders_replacement_product_id` (`replacement_product_id`),
  KEY `idx_service_orders_company_id` (`company_id`),
  KEY `idx_service_orders_payment_status` (`payment_status`),
  KEY `idx_service_orders_priority` (`priority`),
  KEY `idx_service_orders_created_at` (`created_at`),
  KEY `idx_service_orders_status_created` (`status`,`created_at`),
  KEY `idx_service_orders_status_updated` (`status`,`updated_at`)
) ENGINE=InnoDB AUTO_INCREMENT=208 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

